"const fs = require('fs');

async function testOllama() {
    console.log("Testing Ollama API with Gemma...");
    try {
        const response = await fetch('http://localhost:11434/api/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: 'gemma4',
                prompt: 'Hyper-realistic medical 3D rendering of arginine molecular structure, clean white background, professional medical textbook illustration',
                stream: false
            })
        });

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();
        console.log("Response fields:", Object.keys(data));

        if (data.response) {
            console.log("Response start:", data.response.substring(0, 200));
        }
    } catch(e) {
        console.error("Error:", e.message);
    }
}
testOllama();
"

"const { chromium } = require('playwright');
require('dotenv').config();

const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

async function takeAdminSnapshot() {
    console.log('🌐 관리자 페이지 캡처를 시작합니다...');
    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        viewport: { width: 1280, height: 800 }
    });
    const page = await context.newPage();

    try {
        console.log('1. 로그인 페이지 접속...');
        await page.goto(`${WP_URL}/wp-login.php`, { waitUntil: 'networkidle', timeout: 30000 });

        console.log('2. 계정 정보 입력 및 로그인...');
        await page.fill('#user_login', WP_USER);
        await page.fill('#user_pass', WP_PASS);
        await page.click('#wp-submit');

        console.log('3. 대시보드 로딩 대기...');
        await page.waitForLoadState('networkidle');
        await page.waitForTimeout(3000); // UI 렌더링을 위해 약간 대기

        console.log('4. 스크린샷 캡처 중...');
        await page.screenshot({ path: 'wp-admin-dashboard.png', fullPage: true });

        console.log('✅ 캡처 완료: wp-admin-dashboard.png');
    } catch (e) {
        console.error('❌ 에러:', e.message);
    } finally {
        await browser.close();
    }
}

takeAdminSnapshot();
"
